{ RED, GREEN, BLUE } colour;
switch ( colour )
{
case RED:
next = GREEN;
break;
case GREEN:
next = BLUE;
break;
case BLUE:
next = RED;
break;
/* Non-compliant - no default label.
* Even though all values of the enumeration are
* handled there is no guarantee that colour takes
* one of those values */
}
